#include<bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a:b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int n,k,f[2005][2005],sz[2005];
vector<PII> g[2005];
int qp(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)
		{
			ans=ans*a;
		}
		a=a*a;
		b>>=1;
	}
	return ans;
}
void dfs(int u,int fa)//DFS
{
	sz[u]=1;
	FOI(s,g[u])
	{
		int v=s.fst;
		int w=s.snd;
		if(v==fa)
		{
			continue;
		}
		dfs(v,u);
		ROF(x,sz[u],0)
		{
			ROF(y,sz[v],0)
			{
				if(x+y>k)
				{
					continue;
				}
				int t=y*(k-y)+(sz[v]-y)*(n-k-sz[v]+y);
				f[u][x+y]=max(f[u][x+y],f[u][x]+f[v][y]+w*t);//树上背包dp
			}
		}
		sz[u]+=sz[v];
	}
}
signed main(void)
{
	IOS
	cin>>n>>k;
	FOR(i,1,n-1)
	{
		int u,v,w;
		cin>>u>>v>>w;
		g[u].pb(mk(v,w));//双向图
		g[v].pb(mk(u,w));
	}
	dfs(1,0);
	cout<<f[1][k];
	return false;
}
